   815→        onAllEvents={recurringAction === 'edit' ? handleEditAllEvents : handleDeleteAllEvents}
   816→        action={recurringAction}
   817→        eventTitle={pendingRecurringEvent?.title || ''}
   818→      />
   819→    </Widget>
   820→  );
   821→};
   822→
   823→// ==================== MONTH VIEW COMPONENT ====================
   824→
   825→interface MonthViewProps {
   826→  currentDate: Date;
   827→  events: Record<string, CalendarEvent[]>;
   828→  tasks: Task[];
   829→  onDayClick: (dateKey: string) => void;
   830→}
   831→
   832→const MonthView: React.FC<MonthViewProps> = ({
   833→  currentDate,
   834→  events,
   835→  tasks,
   836→  onDayClick,
   837→}) => {
   838→  const year = currentDate.getFullYear();
   839→  const month = currentDate.getMonth();
   840→
   841→  const firstDay = getFirstDayOfMonth(currentDate);
   842→  const daysInMonth = getDaysInMonth(currentDate);
   843→  const daysInPrevMonth = getDaysInPrevMonth(currentDate);
   844→
   845→  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   846→
   847→  // Generate day cells
   848→  const dayCells = useMemo(() => {
   849→    const cells = [];
   850→
   851→    // Previous month days
   852→    for (let i = firstDay - 1; i >= 0; i--) {
   853→      const dayNum = daysInPrevMonth - i;
   854→      const date = new Date(year, month - 1, dayNum);
   855→      cells.push({
   856→        date,
   857→        dayNum,
   858→        isOtherMonth: true,
   859→        isToday: false,
   860→        dateKey: getLegacyDateKey(date),
   861→      });
   862→    }
   863→
   864→    // Current month days
   865→    for (let i = 1; i <= daysInMonth; i++) {
   866→      const date = new Date(year, month, i);
   867→      const dateKey = getLegacyDateKey(date);
   868→      cells.push({
   869→        date,
   870→        dayNum: i,
   871→        isOtherMonth: false,
   872→        isToday: isToday(date),
   873→        dateKey,
   874→      });
   875→    }
   876→
   877→    // Next month days (to fill grid)
   878→    const totalCells = cells.length;
   879→    const remainingCells = 35 - totalCells;
   880→    for (let i = 1; i <= remainingCells; i++) {
   881→      const date = new Date(year, month + 1, i);
   882→      cells.push({
   883→        date,
   884→        dayNum: i,
   885→        isOtherMonth: true,
   886→        isToday: false,
   887→        dateKey: getLegacyDateKey(date),
   888→      });
   889→    }
   890→
   891→    return cells;
   892→  }, [year, month, firstDay, daysInMonth, daysInPrevMonth]);
   893→
   894→  // Filter tasks with date ranges (memoized to avoid re-filtering on every render)
   895→  const tasksWithDates = useMemo(
   896→    () => tasks.filter((task) => task.startDate && task.dueDate),
   897→    [tasks]
   898→  );
   899→
   900→  return (
   901→    <div className="calendar-month-view flex-1 grid grid-rows-[auto_1fr] gap-2">
   902→      {/* Day headers */}
   903→      <div className="grid grid-cols-7 gap-1">
   904→        {days.map((day) => (
   905→          <div
   906→            key={day}
   907→            className="calendar-day-header text-center font-semibold text-sm text-text-light-secondary dark:text-text-dark-secondary py-2"
   908→          >
   909→            {day}
   910→          </div>
   911→        ))}
   912→      </div>
   913→
   914→      {/* Day cells */}
   915→      <div className="grid grid-cols-7 grid-rows-5 gap-1">
   916→        {dayCells.map((cell, index) => {
   917→          const hasEvent = (events[cell.dateKey]?.length || 0) > 0;
   918→
   919→          return (
   920→            <DayCell
   921→              key={index}
   922→              date={cell.date}
   923→              dayNum={cell.dayNum}
   924→              isOtherMonth={cell.isOtherMonth}
   925→              isToday={cell.isToday}
   926→              hasEvent={hasEvent}
   927→              dateKey={cell.dateKey}
   928→              tasks={tasksWithDates}
   929→              events={events}
   930→              onClick={() => !cell.isOtherMonth && onDayClick(cell.dateKey)}
   931→            />
   932→          );
   933→        })}
   934→      </div>
   935→    </div>
   936→  );
   937→};
   938→
   939→// ==================== DAY CELL COMPONENT ====================
   940→
   941→interface DayCellProps {
   942→  date: Date;
   943→  dayNum: number;
   944→  isOtherMonth: boolean;
   945→  isToday: boolean;
   946→  hasEvent: boolean;
   947→  dateKey: string;
   948→  tasks: Task[];
   949→  events: Record<string, CalendarEvent[]>;
   950→  onClick: () => void;
   951→}
   952→
   953→const DayCellComponent: React.FC<DayCellProps> = ({
   954→  date,
   955→  dayNum,
   956→  isOtherMonth,
   957→  isToday,
   958→  hasEvent,
   959→  dateKey,
   960→  tasks,
   961→  events,
   962→  onClick,
   963→}) => {
   964→  // Find tasks that overlap this day
   965→  const overlappingTasks = tasks.filter((task) => {
   966→    const startDate = new Date(task.startDate!);
   967→    const dueDate = new Date(task.dueDate!);
   968→    return isDateBetween(date, startDate, dueDate);
   969→  });
   970→
   971→  const priorityColors = {
   972→    low: 'bg-accent-cyan',
   973→    medium: 'bg-status-warning',
   974→    high: 'bg-status-error',
   975→  };
   976→
   977→  return (
   978→    <div
   979→      onClick={onClick}
   980→      className={`
   981→        calendar-day
   982→        relative
   983→        border rounded
   984→        p-2
   985→        max-h-[120px]
   986→        aspect-square
   987→        cursor-pointer
   988→        transition-all
   989→        hover:shadow-md
   990→        ${isOtherMonth ? 'bg-neutral-100 dark:bg-neutral-700 opacity-50' : 'bg-surface-light-elevated dark:bg-neutral-800'}
   991→        ${isToday ? 'ring-2 ring-accent-cyan' : 'border-neutral-200 dark:border-neutral-700'}
   992→        ${hasEvent ? 'border-accent-magenta' : ''}
   993→      `}
   994→    >
   995→      {/* Day number */}
   996→      <div
   997→        className={`
   998→          calendar-day-number
   999→          text-sm font-semibold
  1000→          ${isToday ? 'text-accent-cyan' : 'text-text-light-secondary dark:text-text-dark-secondary'}
  1001→        `}
  1002→      >
  1003→        {dayNum}
  1004→      </div>
  1005→
  1006→      {/* Event indicator dot */}
  1007→      {hasEvent && (
  1008→        <div className="absolute top-1 right-1 w-2 h-2 bg-accent-magenta rounded-full"></div>
  1009→      )}
  1010→
  1011→      {/* Event text (if no tasks to show room for) */}
  1012→      {hasEvent && overlappingTasks.length === 0 && (
  1013→        <div className="mt-1 space-y-1">
  1014→          {events[dateKey].slice(0, 2).map((event) => {
  1015→            const showLeftArrow = event._isMultiDayPart && !event._isMultiDayFirst;
  1016→            const showRightArrow = event._isMultiDayPart && !event._isMultiDayLast;
  1017→            return (
  1018→              <div
  1019→                key={event.id}
  1020→                className="text-xs text-accent-magenta font-medium truncate px-1 flex items-center gap-0.5"
  1021→              >
  1022→                {showLeftArrow && <span className="text-accent-magenta">←</span>}
  1023→                <span className="flex-1 truncate">{event.title}</span>
  1024→                {showRightArrow && <span className="text-accent-magenta">→</span>}
  1025→              </div>
  1026→            );
  1027→          })}
  1028→          {events[dateKey].length > 2 && (
  1029→            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary px-1">
  1030→              +{events[dateKey].length - 2} more
  1031→            </div>
  1032→          )}
  1033→        </div>
  1034→      )}
  1035→
  1036→      {/* Task bars */}
  1037→      <div className="mt-1 space-y-1">
  1038→        {overlappingTasks.slice(0, 2).map((task) => (
  1039→          <div
  1040→            key={task.id}
  1041→            className={`
  1042→              calendar-task-bar
  1043→              text-xs
  1044→              px-1
  1045→              py-0.5
  1046→              rounded
  1047→              text-white
  1048→              truncate
  1049→              ${priorityColors[task.priority || 'medium']}
  1050→            `}
  1051→            title={task.title}
  1052→          >
  1053→            {task.title}
  1054→          </div>
  1055→        ))}
  1056→        {overlappingTasks.length > 2 && (
  1057→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
  1058→            +{overlappingTasks.length - 2} more
  1059→          </div>
  1060→        )}
  1061→      </div>
  1062→    </div>
  1063→  );
  1064→};
  1065→
  1066→// Memoize DayCell to prevent unnecessary re-renders (35 cells per month view)
  1067→const DayCell = React.memo(DayCellComponent, (prevProps, nextProps) => {
  1068→  return (
  1069→    prevProps.dayNum === nextProps.dayNum &&
  1070→    prevProps.isOtherMonth === nextProps.isOtherMonth &&
  1071→    prevProps.isToday === nextProps.isToday &&
  1072→    prevProps.hasEvent === nextProps.hasEvent &&
  1073→    prevProps.dateKey === nextProps.dateKey &&
  1074→    prevProps.tasks.length === nextProps.tasks.length
  1075→  );
  1076→});
