     1→/**
     2→ * Recurrence Utility Functions
     3→ *
     4→ * Generates recurring event instances based on recurrence rules
     5→ * Supports daily, weekly, monthly, yearly frequencies
     6→ */
     7→
     8→import type { CalendarEvent } from '../types';
     9→import { format, addDays, addWeeks, addMonths, addYears, parseISO, isBefore, isAfter } from 'date-fns';
    10→
    11→interface RecurrenceInstance {
    12→  date: string; // YYYY-MM-DD
    13→  event: CalendarEvent;
    14→}
    15→
    16→/**
    17→ * Generate recurring event instances for a date range
    18→ */
    19→export const generateRecurringInstances = (
    20→  event: CalendarEvent,
    21→  baseDate: string, // YYYY-MM-DD
    22→  startDate: Date,
    23→  endDate: Date
    24→): RecurrenceInstance[] => {
    25→  if (!event.recurrence) return [];
    26→
    27→  const instances: RecurrenceInstance[] = [];
    28→  const { frequency, interval, daysOfWeek, dayOfMonth, endType, endCount, endDate: recEndDate } = event.recurrence;
    29→
    30→  let currentDate = parseISO(baseDate);
    31→  let count = 0;
    32→
    33→  // Determine max occurrences
    34→  const maxOccurrences = endType === 'after' && endCount ? endCount : 1000; // Safety limit
    35→
    36→  while (count < maxOccurrences) {
    37→    // Check if current date is within view range
    38→    if (!isBefore(currentDate, startDate) && !isAfter(currentDate, endDate)) {
    39→      // For weekly: check if current day matches daysOfWeek
    40→      if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
    41→        const dayOfWeek = currentDate.getDay();
    42→        if (daysOfWeek.includes(dayOfWeek)) {
    43→          instances.push({
    44→            date: format(currentDate, 'yyyy-MM-dd'),
    45→            event: {
    46→              ...event,
    47→              recurrenceId: event.id,
    48→              id: `${event.id}-${format(currentDate, 'yyyy-MM-dd')}`,
    49→            },
    50→          });
    51→        }
    52→      } else {
    53→        // For other frequencies, include every occurrence
    54→        instances.push({
    55→          date: format(currentDate, 'yyyy-MM-dd'),
    56→          event: {
    57→            ...event,
    58→            recurrenceId: event.id,
    59→            id: `${event.id}-${format(currentDate, 'yyyy-MM-dd')}`,
    60→          },
    61→        });
    62→      }
    63→    }
    64→
    65→    // Move to next occurrence
    66→    switch (frequency) {
    67→      case 'daily':
    68→        currentDate = addDays(currentDate, interval);
    69→        break;
    70→      case 'weekly':
    71→        currentDate = addWeeks(currentDate, interval);
    72→        break;
    73→      case 'monthly':
    74→        currentDate = addMonths(currentDate, interval);
    75→        // If dayOfMonth specified, set to that day
    76→        if (dayOfMonth) {
    77→          currentDate.setDate(Math.min(dayOfMonth, new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0).getDate()));
    78→        }
    79→        break;
    80→      case 'yearly':
    81→        currentDate = addYears(currentDate, interval);
    82→        break;
    83→    }
    84→
    85→    count++;
    86→
    87→    // Check end conditions
    88→    if (endType === 'until' && recEndDate) {
    89→      const endDateParsed = parseISO(recEndDate);
    90→      if (isAfter(currentDate, endDateParsed)) {
    91→        break;
    92→      }
    93→    }
    94→
    95→    if (endType === 'after' && count >= (endCount || 0)) {
    96→      break;
    97→    }
    98→
    99→    // Safety: stop if we've generated instances far beyond the end date
   100→    if (isAfter(currentDate, addYears(endDate, 10))) {
   101→      break;
   102→    }
   103→  }
   104→
   105→  return instances;
   106→};
   107→
   108→/**
   109→ * Get all instances of a recurring event for display in calendar
   110→ */
   111→export const getEventInstances = (
   112→  event: CalendarEvent,
   113→  baseDate: string,
   114→  viewStartDate: Date,
   115→  viewEndDate: Date
   116→): Map<string, CalendarEvent[]> => {
   117→  const instancesMap = new Map<string, CalendarEvent[]>();
   118→
   119→  if (!event.recurrence) {
   120→    // Non-recurring event
   121→    const existingEvents = instancesMap.get(baseDate) || [];
   122→    instancesMap.set(baseDate, [...existingEvents, event]);
   123→    return instancesMap;
   124→  }
   125→
   126→  // Generate recurring instances
   127→  const instances = generateRecurringInstances(event, baseDate, viewStartDate, viewEndDate);
   128→
   129→  instances.forEach(({ date, event: instanceEvent }) => {
   130→    const existingEvents = instancesMap.get(date) || [];
   131→    instancesMap.set(date, [...existingEvents, instanceEvent]);
   132→  });
   133→
   134→  return instancesMap;
   135→};
   136→
   137→/**
   138→ * Check if a date has a specific day of week
   139→ */
   140→export const isDayOfWeek = (date: Date, dayOfWeek: number): boolean => {
   141→  return date.getDay() === dayOfWeek;
   142→};
   143→
   144→/**
   145→ * Expand multi-day event across date range
   146→ */
   147→export const expandMultiDayEvent = (
   148→  event: CalendarEvent,
   149→  startDateKey: string
   150→): Map<string, CalendarEvent> => {
   151→  const result = new Map<string, CalendarEvent>();
   152→
   153→  if (!event.endDate || event.endDate === startDateKey) {
   154→    // Single-day event
   155→    result.set(startDateKey, event);
   156→    return result;
   157→  }
   158→
   159→  // Multi-day event: create instance for each day
   160→  const startDate = parseISO(startDateKey);
   161→  const endDate = parseISO(event.endDate);
   162→
   163→  let currentDate = startDate;
   164→  let dayIndex = 0;
